if (!$env.GDA_API_KEY_2026 || !$env.GDA_DEPLOY_KEY_2026 || !$env.GDA_WEBHOOK_SECRET_2026) throw new Error('2026 auth env vars not set');
const headers = $input.first().json.headers || {};
const body = $input.first().json.body || {};
const auth = headers["x-gda-auth"] || headers["x-gda-key"] || body.auth_key || body.deploy_key || "";
const validKeys = [$env.GDA_DEPLOY_KEY_2026, $env.GDA_API_KEY_2026, $env.GDA_WEBHOOK_SECRET_2026];
if (!validKeys.includes(auth)) {
  const origin = (headers.origin || headers.referer || "").toLowerCase();
  const trusted = ["gda.csr-llc.tech","n8n.csr-llc.tech","localhost","gdacommand.retool.com"];
  if (!trusted.some(o => origin.includes(o))) throw new Error("Unauthorized");
}
return [{ json: body }];

const body = $input.first()?.json?.body || $input.first()?.json || {};
if (body.action === 'history') {
  return [];
}
return [{ json: { target: body.target || 'Unknown Target', target_type: body.target_type || 'agency', session_id: body.session_id || ('ooda_' + Date.now()) } }];

const target = $('Extract Inputs').first()?.json?.target || 'Unknown';
const targetType = $('Extract Inputs').first()?.json?.target_type || 'agency';
const sessionId = $('Extract Inputs').first()?.json?.session_id || '';
const intel = ($('Fetch Recent Intel').all()||[]).map(i=>i.json).filter(i=>i&&!i.error);
const cache = ($('Fetch Competitor Cache').all()||[]).map(i=>i.json).filter(i=>i&&!i.error);
const alerts = ($('Fetch Active Alerts').all()||[]).map(i=>i.json).filter(i=>i&&!i.error);
const news = (($('Tavily News Search').first()?.json?.results)||[]).slice(0,5);

function clean(s, maxLen) {
  return String(s||'')
    .replace(/[\r\n\t]+/g,' ')
    .replace(/[^\x20-\x7E]/g,'')
    .replace(/"/g,"'")
    .replace(/\\+/g,'')
    .trim()
    .substring(0, maxLen||120);
}

function extractFinding(f) {
  const s = clean(f, 400);
  if (s.includes('GDA EXECUTIVE SITREP') || s.includes('BLUF')) {
    const blufIdx = s.indexOf('BLUF');
    if (blufIdx > -1) {
      const afterBluf = s.substring(blufIdx + 4).replace(/[^a-zA-Z]/,'').trim();
      return afterBluf.substring(0, 150);
    }
  }
  const pipeIdx = s.indexOf(' | ');
  const periodIdx = s.indexOf('. ');
  if (pipeIdx > 20) return s.substring(0, pipeIdx).trim().substring(0,150);
  if (periodIdx > 20) return s.substring(0, periodIdx).trim().substring(0,150);
  return s.substring(0,150);
}

const intelLines = intel.slice(0,5).map((i,idx)=> `${idx+1}. [${clean(i.category,15)}] ${extractFinding(i.finding)}`);
const alertLines = alerts.slice(0,5).map((i,idx)=> `${idx+1}. [${clean(i.urgency,8)}] ${clean(i.title,60)}: ${clean(i.detail,100)}`);
const newsLines = news.slice(0,5).map((n,idx)=> `${idx+1}. ${clean(n.title,100)}`);

let cacheLines = ['No cached data'];
if (cache[0] && cache[0].full_11q_result) {
  const r = cache[0].full_11q_result;
  const spend = r.how_much_spend || {};
  const vendors = (r.who_buying_from||[]).slice(0,3).map(v=>`${clean(v.vendor,30)} ${clean(v.award_total,20)}`).join(' | ');
  const h2h = (r.head_to_head||[]).map(h=>`${clean(h.competitor,20)}: ${clean(h.verdict,15)}`).join(' | ');
  const fit = r.eis_opportunities||{};
  cacheLines = [
    `Spend FY25: ${clean(spend.fy2025_total,20)} FY26PB: ${clean(spend.fy2026_pb_request,20)} Trend: ${clean(spend.trend,10)}`,
    `Top vendors: ${vendors}`,
    `H2H: ${h2h}`,
    `EIS fit: ${clean(fit.overall_fit,15)} pWin: ${clean(fit.pwin_estimate,50)}`
  ];
}

const dataBlock = `INTEL FINDINGS:\n${intelLines.join('\n') || 'None'}\n\nACTIVE ALERTS:\n${alertLines.join('\n') || 'None'}\n\nRECENT NEWS:\n${newsLines.join('\n') || 'None'}\n\nCACHED DATA:\n${cacheLines.join('\n')}`;

let roleContext = '';
let analysisInstructions = '';
let jsonTemplate = '';

const shipleyDecideFields = ',"past_performance":{"has_direct_experience":false,"detail":"GDA past performance assessment with this target","suggested_partners":["partner type needed with rationale"]},"timeline_analysis":{"expected_release":"date or Unknown","days_until_release":0,"shipley_phase":"Shaping Opportunity|Capture Phase|Proposal-Ready Window"},"competitive_landscape":{"incumbents":["company - key strength"],"competitors":["competitor - why they will bid"],"gda_differentiators":["key GDA differentiator"]},"teaming_recommendations":["Need [type] partner with [capability/clearance/past performance]"],"shipley_gate_check":{"current_phase":"Phase 0 Market Assessment|Phase 1 Pursuit|Phase 2 Capture|Phase 3 Proposal","gate_criteria":["criterion to advance"],"actions_needed_now":["action1","action2","action3"]}';

if (targetType === 'competitor') {
  roleContext = `You are a competitive intelligence analyst for GDA (Georgetown Defense Analytics). GDA operates three business units: Envision (XR/simulation/training), PD Systems (C5ISR/AI/ML), and Riverstone (SIGINT/cyber/cleared software). You are analyzing a COMPETITOR.`;
  analysisInstructions = `Analyze ${target} as a COMPETITOR. OBSERVE: What is ${target} winning? Where active? Recent awards? ORIENT: Strengths vs GDA? Vulnerabilities? SWOT. DECIDE: Compete, partner, or avoid? ACT: Outmaneuver actions.`;
  jsonTemplate = `{"observe":{"summary":"competitor summary","intel_count":${intel.length},"alert_count":${alerts.length},"news_count":${news.length},"key_signals":["signal1","signal2","signal3"]},"orient":{"threat_assessment":"SWOT","opportunity_assessment":"vulnerabilities","win_probability":"HIGH/MEDIUM/LOW","win_probability_rationale":"rationale","capability_gaps":["gap1"],"market_forces":"market share","confidence":"HIGH/MEDIUM/LOW"},"decide":{"recommendation":"PURSUE/HOLD/NO-GO","rationale":["r1","r2","r3"]${shipleyDecideFields},"alternatives":["alt1","alt2"],"key_assumptions":["a1"],"decision_triggers":["t1"]},"act":{"immediate_30d":["a1","a2","a3"],"capture_30_90d":["s1","s2"],"proposal_90plus":["l1"],"watch_items":["w1","w2"]},"confidence_score":75,"summary":"BLUF"}`;
} else if (targetType === 'program') {
  roleContext = `You are a capture manager for GDA (Georgetown Defense Analytics). GDA operates three business units: Envision (XR/simulation/training), PD Systems (C5ISR/AI/ML), and Riverstone (SIGINT/cyber/cleared software). You are analyzing a PROGRAM/SOLICITATION.`;
  analysisInstructions = `Analyze ${target} as a PROGRAM. OBSERVE: Status, requirements, timeline. ORIENT: GDA fit, competition, gaps. DECIDE: Bid as prime/sub? Teaming? ACT: Capture actions and milestones.`;
  jsonTemplate = `{"observe":{"summary":"program summary","intel_count":${intel.length},"alert_count":${alerts.length},"news_count":${news.length},"key_signals":["s1","s2","s3"]},"orient":{"threat_assessment":"requirements fit","opportunity_assessment":"value and timeline","win_probability":"HIGH/MEDIUM/LOW","win_probability_rationale":"rationale","capability_gaps":["gap1"],"market_forces":"acq timeline","confidence":"HIGH/MEDIUM/LOW"},"decide":{"recommendation":"PURSUE/HOLD/NO-GO","rationale":["r1","r2","r3"]${shipleyDecideFields},"alternatives":["alt1"],"key_assumptions":["a1"],"decision_triggers":["t1"]},"act":{"immediate_30d":["a1","a2","a3"],"capture_30_90d":["s1","s2"],"proposal_90plus":["l1"],"watch_items":["w1"]},"confidence_score":75,"summary":"BLUF"}`;
} else {
  roleContext = `You are a senior capture manager for GDA (Georgetown Defense Analytics). GDA operates three business units: Envision (XR/simulation/training), PD Systems (C5ISR/AI/ML), and Riverstone (SIGINT/cyber/cleared software). You are analyzing a TARGET AGENCY.`;
  analysisInstructions = `Analyze ${target} as a TARGET AGENCY. OBSERVE: Priorities, active/upcoming contracts. ORIENT: GDA mission alignment, budget, vehicles. DECIDE: Pursue? Which BU? ACT: Engagement and positioning actions.`;
  jsonTemplate = `{"observe":{"summary":"agency summary","intel_count":${intel.length},"alert_count":${alerts.length},"news_count":${news.length},"key_signals":["s1","s2","s3"]},"orient":{"threat_assessment":"mission alignment","opportunity_assessment":"budget sizing","win_probability":"HIGH/MEDIUM/LOW","win_probability_rationale":"rationale","capability_gaps":["gap1"],"market_forces":"vehicles and landscape","confidence":"HIGH/MEDIUM/LOW"},"decide":{"recommendation":"PURSUE/HOLD/NO-GO","rationale":["r1","r2","r3"]${shipleyDecideFields},"alternatives":["alt1"],"key_assumptions":["a1"],"decision_triggers":["t1"]},"act":{"immediate_30d":["a1","a2","a3"],"capture_30_90d":["s1","s2"],"proposal_90plus":["l1"],"watch_items":["w1"]},"confidence_score":75,"summary":"BLUF"}`;
}

const shipleyBlock = `MANDATORY DECIDE SECTION (Shipley-aligned capture brief):\n1. PAST PERFORMANCE: Does GDA have direct experience with this target? If not, state 'GDA has no past performance with [target]. Teaming partner required.' and suggest specific partner type.\n2. TIMELINE: Expected release date and days until. <30d=Proposal-Ready Window. 30-90d=Capture Phase. >90d=Shaping Opportunity.\n3. COMPETITIVE LANDSCAPE: Top 3-5 incumbents and competitors with key strengths. Use cached data.\n4. TEAMING: Specific teaming partners needed based on capability gaps (e.g. 'Need 8(a) partner with SOF past performance').\n5. SHIPLEY GATE CHECK: Current Shipley phase, gate criteria to advance, and 3 actions needed NOW.\nThe Decide section must read like a BD executive capture brief.`;

const prompt = `${roleContext}\n\nTARGET: ${target}\nTARGET TYPE: ${targetType.toUpperCase()}\n\n${dataBlock}\n\n${analysisInstructions}\n\n${shipleyBlock}\n\nCRITICAL: Return ONLY a raw JSON object. No markdown. No preamble. Start with { end with }.\nYou MUST populate ALL arrays with at least 2-3 specific, actionable items.\nAll 5 Shipley decide fields are REQUIRED.\n\n${jsonTemplate}`;

return [{ json: { target, targetType, sessionId, prompt, observe_raw: { intel_findings: intel, competitor_cache: cache[0]||null, active_alerts: alerts, recent_news: news.map(n=>({ title: n.title, url: n.url, content: (n.content||'').substring(0,200) })) } } }];

const mergeData = $('Merge Observe Data').first()?.json || {};
const claudeRaw = $input.first()?.json;
let ooda = {};
let parseError = null;

try {
  const text = claudeRaw?.content?.[0]?.text || '{}';
  let clean = text.replace(/```json/gi,'').replace(/```/g,'').trim();
  const start = clean.indexOf('{');
  const end = clean.lastIndexOf('}');
  if (start === -1 || end === -1) throw new Error('No JSON braces found');
  clean = clean.substring(start, end + 1);
  try {
    ooda = JSON.parse(clean);
  } catch(e1) {
    let repaired = clean
      .replace(/[\u2018\u2019]/g, "'")
      .replace(/[\u201C\u201D]/g, '"')
      .replace(/[\x00-\x1f\x7f]/g, ' ')
      .replace(/,\s*}/g, '}').replace(/,\s*]/g, ']');
    ooda = JSON.parse(repaired);
  }
} catch(e) {
  parseError = e.message;
  ooda = { observe: { summary: 'Parse error - see raw data', intel_count: 0, alert_count: 0, news_count: 0, key_signals: [] }, orient: { threat_assessment: 'Manual review required', opportunity_assessment: '', win_probability: 'TBD', win_probability_rationale: parseError, capability_gaps: [], market_forces: '', confidence: 'LOW' }, decide: { recommendation: 'MONITOR', rationale: ['Parse failed'], alternatives: [], key_assumptions: [], decision_triggers: [] }, act: { immediate_30d: ['Review raw data'], capture_30_90d: [], proposal_90plus: [], watch_items: [] }, confidence_score: 0, summary: 'Parse error: ' + parseError };
}

function safeStr(v) {
  if (v === null || v === undefined) return '';
  if (typeof v === 'string') return v;
  if (Array.isArray(v)) return v.filter(function(x){return x;}).join('; ');
  if (typeof v === 'object') return JSON.stringify(v);
  return String(v);
}

const obs = ooda.observe || {};
const ori = ooda.orient || {};
const dec = ooda.decide || {};
const act = ooda.act || {};

return [{ json: {
  target: mergeData.target,
  session_id: mergeData.sessionId,
  summary: safeStr(ooda.summary),
  confidence_score: ooda.confidence_score || 0,
  observe_summary: safeStr(obs.summary),
  observe_intel_count: obs.intel_count || 0,
  observe_alert_count: obs.alert_count || 0,
  observe_news_count: obs.news_count || 0,
  observe_key_signals: (obs.key_signals || []).map(safeStr),
  orient_threat: safeStr(ori.threat_assessment),
  orient_opportunity: safeStr(ori.opportunity_assessment),
  orient_win_probability: safeStr(ori.win_probability),
  orient_win_rationale: safeStr(ori.win_probability_rationale),
  orient_capability_gaps: (ori.capability_gaps || []).map(safeStr),
  orient_market_forces: safeStr(ori.market_forces),
  orient_confidence: safeStr(ori.confidence),
  decide_recommendation: safeStr(dec.recommendation),
  decide_rationale: (dec.rationale || []).map(safeStr),
  decide_alternatives: (dec.alternatives || []).map(safeStr),
  decide_assumptions: (dec.key_assumptions || []).map(safeStr),
  decide_triggers: (dec.decision_triggers || []).map(safeStr),
  act_immediate: (act.immediate_30d || []).map(safeStr),
  act_capture: (act.capture_30_90d || []).map(safeStr),
  act_proposal: (act.proposal_90plus || []).map(safeStr),
  act_watch: (act.watch_items || []).map(safeStr),
  observe: safeStr(obs),
  orient: safeStr(ori),
  decide: safeStr(dec),
  act: safeStr(act),
  raw_observe_data: JSON.stringify(mergeData.observe_raw || {}),
  generated_at: new Date().toISOString()
} }];
